module elevator_system (
	input clk,
	input resetn,
	input request,
	output reg moving);

	parameter IDLE=0, MOVING=1;
	reg elevator_state, next_state;

	always @(posedge clk) begin
		if (~resetn) elevator_state <= IDLE;
		else elevator_state <= next_state;
	end

	always_comb begin
		case (elevator_state)
			IDLE: next_state = request ? MOVING : IDLE;
			MOVING: next_state = IDLE;
			default: next_state = IDLE;
		endcase
	end

	always @(elevator_state) begin
		case (elevator_state)
			MOVING: moving = 1;
			default: moving = 0;
		endcase
	end
endmodule
